"""Source-code slicer for CodeEval minimization.

Public entry point: slice_source(file_path, eval_target, language) -> str

Extracts the named eval declaration plus all same-file top-level definitions it
references transitively (BFS), plus all top-level import statements verbatim.
Falls back to full-file content on any failure or empty output.
"""
from __future__ import annotations

import warnings
from collections import deque
from typing import Any


# ---------------------------------------------------------------------------
# Language config
# ---------------------------------------------------------------------------

_LANG_CONFIG: dict[str, dict[str, Any]] = {
    "python": {
        "root_type": "module",
        "import_types": {"import_statement", "import_from_statement"},
        "fn_types": {"function_definition", "class_definition"},
        "decorated_type": "decorated_definition",
    },
    "typescript": {
        "root_type": "program",
        "import_types": {"import_statement"},
        "fn_types": {
            "function_declaration",
            "class_declaration",
            "lexical_declaration",
            "abstract_class_declaration",
        },
        "export_wrapper": "export_statement",
    },
}


# ---------------------------------------------------------------------------
# Name extraction helpers
# ---------------------------------------------------------------------------

def _get_identifier_text(node: Any) -> str | None:
    for child in node.children:
        if child.type == "identifier":
            return child.text.decode("utf-8")
    return None


def _get_py_top_level_name(node: Any) -> str | None:
    cfg = _LANG_CONFIG["python"]
    if node.type in cfg["fn_types"]:
        return _get_identifier_text(node)
    if node.type == cfg["decorated_type"]:
        # wrapped function or class
        for child in node.children:
            name = _get_py_top_level_name(child)
            if name:
                return name
    assignment_name = _get_py_assignment_name(node)
    if assignment_name:
        return assignment_name
    return None


def _get_py_assignment_name(node: Any) -> str | None:
    assignment = None
    if node.type == "assignment":
        assignment = node
    elif node.type == "expression_statement":
        for child in node.children:
            if child.type == "assignment":
                assignment = child
                break
    if assignment is None:
        return None
    for child in assignment.children:
        if child.type == "identifier":
            return child.text.decode("utf-8")
    return None


def _get_ts_lexical_name(node: Any) -> str | None:
    for child in node.children:
        if child.type == "variable_declarator":
            for sub in child.children:
                if sub.type == "identifier":
                    return sub.text.decode("utf-8")
    return None


def _get_ts_top_level_name(node: Any) -> str | None:
    cfg = _LANG_CONFIG["typescript"]
    if node.type in cfg["fn_types"]:
        if node.type == "lexical_declaration":
            return _get_ts_lexical_name(node)
        return _get_identifier_text(node)
    if node.type == cfg.get("export_wrapper", ""):
        for child in node.children:
            name = _get_ts_top_level_name(child)
            if name:
                return name
    return None


def _get_name(node: Any, language: str) -> str | None:
    if language == "python":
        return _get_py_top_level_name(node)
    return _get_ts_top_level_name(node)


# ---------------------------------------------------------------------------
# Identifier collection
# ---------------------------------------------------------------------------

def _collect_identifiers(node: Any, result: set[str] | None = None) -> set[str]:
    if result is None:
        result = set()
    if node.type == "identifier":
        result.add(node.text.decode("utf-8"))
    for child in node.children:
        _collect_identifiers(child, result)
    return result


# ---------------------------------------------------------------------------
# Core slicer
# ---------------------------------------------------------------------------

def _parse(source: str, language: str) -> Any:
    if language == "python":
        import tree_sitter_python as tspython
        from tree_sitter import Language, Parser
        lang = Language(tspython.language())
    else:
        import tree_sitter_typescript as tstypescript
        from tree_sitter import Language, Parser
        lang = Language(tstypescript.language_typescript())
    parser = Parser(lang)
    return parser.parse(source.encode("utf-8"))


def _build_top_level_map(root: Any, language: str) -> tuple[list[Any], dict[str, Any]]:
    """Return (import_nodes, name_to_node) for top-level children."""
    cfg = _LANG_CONFIG[language]
    import_nodes: list[Any] = []
    name_to_node: dict[str, Any] = {}

    for child in root.children:
        if child.type in cfg["import_types"]:
            import_nodes.append(child)
        else:
            name = _get_name(child, language)
            if name:
                name_to_node[name] = child

    return import_nodes, name_to_node


def _transitive_slice(
    target_name: str,
    name_to_node: dict[str, Any],
) -> list[Any]:
    """BFS over same-file references starting from target_name."""
    visited: set[str] = set()
    queue: deque[str] = deque([target_name])
    ordered: list[Any] = []

    while queue:
        name = queue.popleft()
        if name in visited:
            continue
        visited.add(name)
        node = name_to_node.get(name)
        if node is None:
            continue
        ordered.append(node)
        for ref in _collect_identifiers(node):
            if ref not in visited and ref in name_to_node:
                queue.append(ref)

    return ordered


def _nodes_to_source(nodes: list[Any], source: str) -> str:
    lines = source.splitlines(keepends=True)
    parts: list[str] = []
    for node in nodes:
        start = node.start_point[0]
        end = node.end_point[0] + 1
        parts.append("".join(lines[start:end]))
    return "".join(parts)


# ---------------------------------------------------------------------------
# Public API
# ---------------------------------------------------------------------------

def slice_source(file_path: str, eval_target: str, language: str) -> str:
    """Return a minimized source slice for the named eval.

    Args:
        file_path: Absolute or relative path to the source file.
        eval_target: The eval name (function/const name) to extract.
        language: ``"python"`` or ``"typescript"``.

    Returns:
        The minimized slice as a string.  Falls back to full file content if
        parsing fails or the output would be empty.
    """
    try:
        with open(file_path, encoding="utf-8") as fh:
            source = fh.read()
        return _slice_source_str(source, eval_target, language)
    except Exception as exc:
        warnings.warn(
            f"slicer: falling back to full file for '{eval_target}' in '{file_path}': {exc}",
            stacklevel=2,
        )
        try:
            with open(file_path, encoding="utf-8") as fh:
                return fh.read()
        except Exception:
            return ""


def _slice_source_str(source: str, eval_target: str, language: str) -> str:
    """Core implementation — raises on failure (caller handles fallback)."""
    if language not in _LANG_CONFIG:
        raise ValueError(f"unsupported language: {language!r}")

    tree = _parse(source, language)
    root = tree.root_node
    import_nodes, name_to_node = _build_top_level_map(root, language)

    if eval_target not in name_to_node:
        raise ValueError(f"eval_target '{eval_target}' not found in {language} top-level definitions")

    slice_nodes = _transitive_slice(eval_target, name_to_node)

    import_text = _nodes_to_source(import_nodes, source)
    slice_text = _nodes_to_source(slice_nodes, source)

    result = import_text
    if import_text and slice_text and not import_text.endswith("\n\n"):
        result = import_text.rstrip("\n") + "\n\n" + slice_text
    else:
        result = import_text + slice_text

    if not result.strip():
        raise ValueError("slice produced empty output")

    return result
